import React, { useEffect, useState } from 'react';
import api from '../api';

function UserDashboard() {
  const [user, setUser] = useState(null);
  const [orders, setOrders] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');

  const storedUser = JSON.parse(localStorage.getItem("user"));

  // Fetch user profile and orders
  const fetchData = async () => {
    try {
      setLoading(true);
      const [userRes, ordersRes] = await Promise.all([
        api.post(`/user/${storedUser.id}`),
        api.post(`/orders/history/${storedUser.id}`)
      ]);

      setUser(userRes.data);
      setOrders(ordersRes.data);
    } catch (err) {
      console.error('Error fetching data:', err);
      setError('Failed to load dashboard. Please try again.');
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchData();
  }, []);

  if (loading) return <div className="text-center mt-5">Loading...</div>;
  if (error) return <div className="text-center mt-5 text-danger">{error}</div>;

  // Calculate most ordered food
  const foodCountMap = {};
  orders.forEach(order => {
    order.items.forEach(item => {
      if (foodCountMap[item.food.name]) {
        foodCountMap[item.food.name] += item.quantity;
      } else {
        foodCountMap[item.food.name] = item.quantity;
      }
    });
  });

  const mostOrderedFood = Object.entries(foodCountMap).sort((a, b) => b[1] - a[1])[0];

  return (
    <div className="container mt-4">
      {/* Header */}
      <div className="text-center mb-5">
        <h2 className="fw-bold">Welcome, {user.name} 👋</h2>
        <p className="text-muted">Here’s your dashboard overview</p>
      </div>
            <div className="card shadow-sm mb-4 p-3 text-center">
     
        <h5>{user.name}</h5>
        <p className="mb-1">🎓 {user.Degree}</p>
        <p className="text-muted small mb-2">Roll No: {user.RollNo}</p>
        <span
          className={`badge ${user.role === "admin" ? "bg-danger" : "bg-primary"}`}
        >
          {user.role.toUpperCase()}
        </span>
      </div>
      <div className="row g-4">
        {/* Profile Section */}
        

        {/* Stats Section */}
        <div className="col-md-8">
          <div className="row g-3">
            <div className="col-md-6">
              <div className="card shadow-sm border-0 p-3 text-center">
                <h5>Total Orders</h5>
                <p className="display-6 fw-bold">{orders.length}</p>
              </div>
            </div>
            <div className="col-md-6">
              <div className="card shadow-sm border-0 p-3 text-center">
                <h5>Most Ordered Food</h5>
                <p className="display-6 fw-bold">{mostOrderedFood ? mostOrderedFood[0] : '-'}</p>
                {mostOrderedFood && <small className="text-muted">× {mostOrderedFood[1]} times</small>}
              </div>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}

export default UserDashboard;
